const body = $input.first().json.body;
const imageUrl = (body?.image_url || '').trim();
const productName = (body?.product_name || '').trim();
const category = (body?.category || '').trim();
if (!imageUrl) throw new Error('image_url es requerido');
if (!imageUrl.startsWith('http')) throw new Error('image_url invalida: ' + imageUrl.substring(0, 80));
return [{ json: { imageUrl, productName, category } }];

const params = $('Extraer parametros').first().json;
const binary = $input.first().binary?.data;

if (!binary) throw new Error('No se pudo descargar la imagen desde: ' + params.imageUrl);

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = binaryData.toString('base64');
const mimeType = binary.mimeType || 'image/jpeg';

return [{ json: {
  imageUrl: params.imageUrl,
  productName: params.productName,
  category: params.category,
  imageBase64: base64,
  imageMimeType: mimeType
}}];

