const response = $input.first().json;

// Respuesta nativa de Gemini REST API
let rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

if (!rawText) throw new Error('Gemini no devolvio texto. Respuesta: ' + JSON.stringify(response).substring(0, 300));

const clean = rawText.replace(/```json|```/g, '').trim();

let desc;
try {
  desc = JSON.parse(clean);
} catch (e) {
  throw new Error('Gemini no devolvio JSON valido: ' + e.message + ' | Raw: ' + clean.substring(0, 200));
}

const { productName, category } = $('Extraer parametros').first().json;

const enrichedPrompt = [
  'Photorealistic virtual try-on image.',
  `Product: ${productName}${category ? ' (' + category + ')' : ''}.`,
  `Garment type: ${desc.garment_type}, ${desc.silhouette} silhouette, ${desc.fit} fit.`,
  `Primary color: ${desc.primary_color}.`,
  desc.secondary_colors?.length ? `Secondary colors: ${desc.secondary_colors.join(', ')}.` : '',
  desc.patterns ? `Patterns and graphics: ${desc.patterns}.` : '',
  `Material/texture: ${desc.materials}.`,
  `Design details - neckline: ${desc.design_details?.neckline || 'n/a'}, sleeves: ${desc.design_details?.sleeves || 'n/a'}, closures: ${desc.design_details?.closures || 'n/a'}${desc.design_details?.pockets ? ', pockets: ' + desc.design_details.pockets : ''}${desc.design_details?.other ? ', other: ' + desc.design_details.other : ''}.`,
  'CRITICAL RULES:',
  '1. Reproduce the product EXACTLY: same colors, patterns, textures, logos, cuts and design details. Do NOT alter any visual element.',
  '2. Keep the persons face, skin tone, hair and body proportions identical to the selfie.',
  '3. The product must fit naturally on the persons body, respecting their pose and lighting.',
  '4. Maintain photorealistic quality with consistent lighting between person and product.',
  '5. Output only the final try-on image.',
].filter(Boolean).join(' ');

return [{ json: { description: desc, enrichedPrompt } }];

const { enrichedPrompt, description: d } = $input.first().json;

const parts = [];
if (d.garment_type) parts.push(d.garment_type + (d.silhouette ? ' de silueta ' + d.silhouette : ''));
if (d.primary_color) parts.push('Color principal: ' + d.primary_color);
if (d.secondary_colors?.length) parts.push('Colores secundarios: ' + d.secondary_colors.join(', '));
if (d.patterns) parts.push('Estampado: ' + d.patterns);
if (d.materials) parts.push('Material: ' + d.materials);
const dd = d.design_details || {};
const details = [
  dd.neckline && 'cuello ' + dd.neckline,
  dd.sleeves && 'mangas ' + dd.sleeves,
  dd.closures && 'cierre ' + dd.closures,
  dd.pockets && 'bolsillos: ' + dd.pockets,
  dd.other || null
].filter(Boolean);
if (details.length) parts.push('Detalles: ' + details.join(', '));
if (d.fit) parts.push('Fit: ' + d.fit);

const CATEGORY_MAP = {
  vestido: 'VESTIDO', dress: 'VESTIDO',
  camisa: 'CAMISA', shirt: 'CAMISA', top: 'TOP', blusa: 'BLUSA', blouse: 'BLUSA',
  pantalon: 'PANTALON', 'pantalón': 'PANTALON', pants: 'PANTS', jeans: 'JEANS',
  falda: 'FALDA', skirt: 'FALDA',
  zapatos: 'ZAPATOS', shoes: 'ZAPATOS', calzado: 'ZAPATOS', footwear: 'ZAPATOS',
  conjunto: 'CONJUNTO', set: 'SET', outfit: 'CONJUNTO',
  chaqueta: 'CHAQUETA', jacket: 'JACKET', abrigo: 'ABRIGO', coat: 'ABRIGO',
  hoodie: 'HOODIE', sudadera: 'HOODIE',
  accesorio: 'ACCESSORY', accessory: 'ACCESSORY', accessories: 'ACCESSORY',
  casco: 'HELMET', helmet: 'HELMET',
};

const rawType = (d.garment_type || '').toLowerCase().trim();
const category = CATEGORY_MAP[rawType] || d.garment_type?.toUpperCase() || null;

return [{ json: { description: parts.join('. ') + '.', category, enrichedPrompt } }];
